    fn synth_bars(n: usize, start: f64, daily_drift: f64) -> Vec<HistoricalPriceRow> {
        let mut bars = Vec::with_capacity(n);
        let mut px = start;
        for i in 0..n {
            let base_day = 1 + (i % 28);
            let month = 1 + ((i / 28) % 12);
            let year = 2024 + (i / (28 * 12));
            bars.push(HistoricalPriceRow {
                date: format!("{:04}-{:02}-{:02}", year, month, base_day),
                open: px,
                high: px * 1.005,
                low: px * 0.995,
                close: px,
                adj_close: px,
                volume: 1_000.0,
                change: 0.0,
                change_pct: 0.0,
            });
            px *= 1.0 + daily_drift;
        }
        bars
    }

